import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import Drawer from '@material-ui/core/Drawer';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import AddIcon from '@material-ui/icons/Add';
import DeleteIcon from '@material-ui/icons/Delete';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import { makeStyles } from '@material-ui/core/styles';
import { getPlayers } from '../../api';

const useStyles = makeStyles((theme) => ({
  mainMenuContainer: {
    display: "flex",
    flexFlow: "column wrap",
    height: 300,
    overflow: "auto"
  },
  mainMenuItem: {
    fontSize: '1rem',
    paddingTop: 1,
    paddingBottom: 1,
  },
  subMenuItem: {
    fontSize: '0.2rem',
    paddingTop: 1,
    paddingBottom: 1,
    paddingLeft: theme.spacing(3),
  },
}));

const DrawerMenu = ({ categories, isAuthenticated }) => {
  const classes = useStyles();
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const dispatch = useDispatch();
  const history = useNavigate();
  const players = useSelector((state) => state.players.players);

  const handleDrawerOpen = () => {
    setIsDrawerOpen(true);
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false);
  };

  const listPlayer = (e, mainMenu, sub) => {
    e.preventDefault();
    const categories = [mainMenu, sub];
    dispatch(getPlayers({ name: categories.join(',') }));
    history(`/players/search?searchQuery=${categories.join(',')}`, { redirect: true });
    handleDrawerClose(); // Stäng menyn när ett menyval klickas på
  };

  const renderSubmenu = (subMenu, mainMenu) => {
    return subMenu.map((subItem, index) => {
      const subItemId = subItem ? subItem._id : '';
      const subItemText = subItem || '';

      return (
        <ListItem
          key={`${subItemId}-${index}`}
          button
          onClick={(e) => {
            listPlayer(e, mainMenu, subItem);
          }}
          className={classes.subMenuItem}
        >
          <ListItemText primary={subItemText} />
          {isAuthenticated && (
            <div>
              <IconButton className={classes.iconButton}>
                <DeleteIcon />
              </IconButton>
            </div>
          )}
        </ListItem>
      );
    });
  };

  const filteredCategories = isAuthenticated
    ? categories
    : categories.filter((category) => {
        const hasPlayers = category.subMenu.some((subItem) =>
          players.some(
            (player) =>
              player.category.includes(category.mainMenu) &&
              player.subCategory.includes(subItem)
          )
        );
        return hasPlayers;
      });

  return (
    <div>
      <IconButton
        edge="start"
        color="inherit"
        aria-label="menu"
        onClick={handleDrawerOpen}
      >
        <MenuIcon />
      </IconButton>
      <Drawer anchor="top" open={isDrawerOpen} onClose={handleDrawerClose}>
        <div className={classes.mainMenuContainer}>
          {filteredCategories.map((category) => (
            <div key={category._id}>
              <ListItem className={classes.mainMenuItem}>
                <ListItemText primary={category.mainMenu} />
              </ListItem>
              <List component="div" disablePadding>
                {isAuthenticated && renderSubmenu(category.subMenu, category.mainMenu)}
              </List>
            </div>
          ))}
        </div>
      </Drawer>
    </div>
  );
};

export default DrawerMenu;
